{
  "summary": "This paper proposes leveraging pre-trained language models (LMs) as general policy networks for sequential decision-making tasks, converting all inputs into sequential embeddings and fine-tuning on expert or actively gathered data. It introduces an active data gathering procedure with hindsight relabeling to enable learning without expert demonstrations and demonstrates improved combinatorial generalization and task success on embodied environments like VirtualHome and BabyAI.",
  "strengths": [
    {
      "point": "Novel use of pre-trained language models as general policy networks for interactive decision-making",
      "evidence": "The paper converts goals, observations, and histories into sequential embeddings processed by a GPT-2 based LM, showing improved generalization on novel tasks."
    },
    {
      "point": "Active data gathering procedure enabling learning without expert data",
      "evidence": "The ADG method with hindsight relabeling outperforms RL baselines such as PPO and DQN+HER on complex embodied tasks with sparse rewards."
    },
    {
      "point": "Empirical analysis of factors driving generalization",
      "evidence": "Ablations show that sequential input representation and LM pre-training are critical for performance, while natural language input format is not strictly necessary."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of direct comparisons to recent transformer-based RL or imitation learning methods trained end-to-end",
      "evidence": "The paper compares mainly against PPO, DQN+HER, and uses Decision Transformer only offline on LID-ADG data, missing baselines like Trajectory Transformer or Gato."
    },
    {
      "point": "Reliance on hand-designed hindsight relabeling templates without scalability analysis",
      "evidence": "ADG uses hand-crafted templates for relabeling but lacks ablations or experiments exploring learned or automated relabeling strategies."
    },
    {
      "point": "Insufficient evaluation of modality-agnostic claims and non-language inputs",
      "evidence": "Experiments focus almost exclusively on templated English sentences; no ablations or results with image patches or scene graphs are provided."
    },
    {
      "point": "Missing critical reproducibility details on LM fine-tuning and tokenization for non-language inputs",
      "evidence": "The paper omits learning rates, epochs, optimizer settings, and embedding/tokenization specifics needed to reproduce the method."
    },
    {
      "point": "Evaluation metrics limited to task success rates without sample efficiency, robustness, or statistical significance",
      "evidence": "No learning curves, confidence intervals, or significance tests are reported, limiting assessment of result robustness."
    },
    {
      "point": "Limited discussion of scalability, failure modes, and safety considerations in active data gathering",
      "evidence": "No systematic failure analysis or safety/recovery mechanisms are discussed despite exploration with random and policy actions."
    }
  ],
  "questions": [
    {
      "question": "How does LID compare to recent end-to-end transformer-based RL or imitation learning methods on the same tasks?",
      "motivation": "Direct comparisons are necessary to contextualize the novelty and performance gains of the proposed approach."
    },
    {
      "question": "Can the hand-designed hindsight relabeling templates be replaced or augmented with learned or language model-based relabeling for better scalability?",
      "motivation": "Automating relabeling would improve applicability to new domains and reduce manual engineering."
    },
    {
      "question": "How well does the approach handle non-language input modalities in practice, and what are the challenges in adapting pre-trained LMs to such inputs?",
      "motivation": "Validating modality-agnostic claims is critical for general applicability beyond language-based tasks."
    },
    {
      "question": "What are the effects of LM size, architecture variants, and pre-training domain on policy performance and generalization?",
      "motivation": "Understanding these factors would inform scalability and guide model selection."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
